  ('generalpolice-3218f787-moex-00276', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-111-7ac5ce32', 'sub-generalpolice-3218f787-05', NULL, 'single_choice', '關於新住民社會工作的服務挑戰，下列敘述何者錯誤？', '["由於文化差異和語言溝通不易，社工人員不容易進行家庭動力和問題需求之評估", "多元文化能力和文化覺察，是社工人員提供專業服務時的重要能力", "多元文化覺察能力可透過教育、反思和實務經驗累積", "新住民選擇結婚來臺，應配合夫家期待，不需對自己生活習慣或子女教養表達看法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:31+00:00", "source_pdf_sha1": "246f08078638", "answer_pdf_sha1": "833358795d8d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會學與社會工作", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
